class RetrievalPlugin:
    async def retrieve_docs(self, query: str) -> list[dict]:
        results = vector_store.similarity_search(query, k=5)
        return [{
            'content': doc.page_content,
            'source': doc.metadata['source'],
            'chunk_id': doc.metadata['id']
        } for doc in results]

# Register
plugin = kernel.import_plugin_from_object(RetrievalPlugin(), "rag")

import { Kernel } from '@semantic-kernel/core';
import { OpenAIChatCompletion } from '@semantic-kernel/connectors-ai-openai';

const kernel = Kernel.create({
  chat: {
    OpenAIChatCompletion({ modelId: 'gpt-4', apiKey: process.env.OPENAI_API_KEY })
  }
});

const planner = kernel.createHandlebarsPlanner();
const plan = await planner.createPlan([
  'rag|retrieve_docs',
  'rag|synthesize_with_sources'
]);
const result = await plan.invokeAsync({ query: 'Explain RAG' });

async function synthesizeWithSources(context: ChatHistory, sources: Document[]) {
  const prompt = `Answer using only these sources:\n${sources.map(s => `[${s.metadata.id}] ${s.pageContent}`).join('\n')}

Answer: `;

  const result = await kernel.invoke('gpt-4', {
    prompt,
    maxTokens: 1000
  });

  return {
    answer: result,
    sources: sources.map(s => s.metadata)
  };
}

