import { VexClient } from 'vex-sdk';

const vex = new VexClient({ apiKey: 'your-vex-key' });

kernel.registerFunctionResultHandler(async (result, context) => {
  if (context.function.name.startsWith('rag')) {
    const verdict = await vex.verify({
      policy: 'rag-high-risk',
      input: context.variables.query,
      output: result.toString(),
      verifications: ['source_faithfulness', 'hallucination_detection', 'citation_accuracy'],
      sources: context.variables.sources || []
    });

    if (!verdict.passed) {
      throw new Error(`Vex blocked: ${verdict.reason}`);
    }
  }
  return result;
});
